app.post('/authorize', (req, res) => {
  const { username, password, client_id, redirect_uri, scope, state, response_type } = req.body;

  if (!username || !password) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing username or password' });
  }

  const user = users[username];
  if (!user || user.password !== password) {
    return res.status(401).send('Invalid credentials');
  }

  if (!client_id || !clients[client_id]) {
    return res.status(400).json({ error: 'invalid_client' });
  }

  if (!validateRedirectUri(client_id, redirect_uri)) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Invalid redirect_uri' });
  }

  const code = generateCode();
  
  authorizationCodes.set(code, {
    client_id,
    redirect_uri,
    user_id: user.user_id,
    scope: scope || '',
    expires_at: Date.now() + 600000,
    used: false
  });

  setTimeout(() => {
    authorizationCodes.delete(code);
  }, 600000);

  const params = {
    code,
    ...(state && { state })
  };

  const redirectUrl = `${redirect_uri}?${querystring.stringify(params)}`;
  res.redirect(redirectUrl);
});

app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret } = req.body;

  const authHeader = req.headers.authorization;
  let clientIdToUse = client_id;
  let clientSecretToUse = client_secret;

  if (authHeader && authHeader.startsWith('Basic ')) {
    const credentials = Buffer.from(authHeader.slice(6), 'base64').toString('utf-8');
    const [id, secret] = credentials.split(':');
    clientIdToUse = id;
    clientSecretToUse = secret;
  }

  if (!grant_type || grant_type !== 'authorization_code') {
    return res.status(400).json({ error: 'unsupported_grant_type' });
  }

  if (!code) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing code' });
  }

  if (!clientIdToUse || !clientSecretToUse) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Missing client credentials' });
  }

  const client = clients[clientIdToUse];
  if (!client || client.client_secret !== clientSecretToUse) {
    return res.status(401).json({ error: 'invalid_client' });
  }

  const codeData = authorizationCodes.get(code);
  if (!codeData) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Invalid or expired code' });
  }

  if (codeData.used) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Code already used' });
  }

  if (codeData.expires_at < Date.now()) {
    authorizationCodes.delete(code);
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Code expired' });
  }

  if (codeData.client_id !== clientIdToUse) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Client mismatch' });
  }

  if (codeData.redirect_uri !== redirect_uri) {
    return res.status(400).json({ error: 'invalid_grant', error_description: 'Redirect URI mismatch' });
  }

  codeData.used = true;

  const accessToken = generateToken();
  const refreshToken = generateToken();

  accessTokens.set(accessToken, {
    client_id: clientIdToUse,
    user_id: codeData.user_id,
    scope: codeData.scope,
    expires_at: Date.now() + 3600000
  });

  setTimeout(() => {
    accessTokens.delete(accessToken);
  }, 3600000);

  authorizationCodes.delete(code);

  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: 3600,
    refresh_token: refreshToken,
    scope: codeData.scope
  });
});

app.get('/userinfo', (req, res) => {
  const authHeader = req.headers.authorization;
  
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens.get(token);

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token' });
  }

  if (tokenData.expires_at < Date.now()) {
    accessTokens.delete(token);
    return res.status(401).json({ error: 'token_expired' });
  }

  res.json({
    user_id: tokenData.user_id,
    scope: tokenData.scope
  });
});

